1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	  <meta charset="UTF-8" />
5	  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
6	  <title>{{userName}}</title>
7	  <style>
8	    :root {
9	      --bg: #0f1115;
10	      --surface: #171a21;
11	      --text: #e8eaf0;
12	      --muted: #9aa3b2;
13	      --accent: #6ea8fe;
14	      --border: #262b36;
15	    }
16	
17	    * {
18	      margin: 0;
19	      padding: 0;
20	      box-sizing: border-box;
21	    }
22	
23	    html {
24	      scroll-behavior: smooth;
25	    }
26	
27	    body {
28	      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
29	      background: var(--bg);
30	      color: var(--text);
31	      line-height: 1.6;
32	      -webkit-font-smoothing: antialiased;
33	    }
34	
35	    .container {
36	      max-width: 720px;
37	      margin: 0 auto;
38	      padding: 0 24px;
39	    }
40	
41	    /* Header / hero */
42	    header {
43	      padding: 96px 0 64px;
44	    }
45	
46	    .avatar {
47	      width: 88px;
48	      height: 88px;
49	      border-radius: 50%;
50	      background: linear-gradient(135deg, var(--accent), #b388ff);
51	      display: flex;
52	      align-items: center;
53	      justify-content: center;
54	      font-size: 32px;
55	      font-weight: 700;
56	      color: #0f1115;
57	      margin-bottom: 24px;
58	    }
59	
60	    h1 {
61	      font-size: 40px;
62	      font-weight: 700;
63	      letter-spacing: -0.02em;
64	      margin-bottom: 8px;
65	    }
66	
67	    .tagline {
68	      font-size: 20px;
69	      color: var(--muted);
70	      margin-bottom: 24px;
71	    }
72	
73	    .intro {
74	      font-size: 17px;
75	      color: var(--text);
76	      max-width: 60ch;
77	    }
78	
79	    /* Sections */
80	    section {
81	      padding: 40px 0;
82	      border-top: 1px solid var(--border);
83	    }
84	
85	    h2 {
86	      font-size: 14px;
87	      font-weight: 600;
88	      text-transform: uppercase;
89	      letter-spacing: 0.08em;
90	      color: var(--muted);
91	      margin-bottom: 24px;
92	    }
93	
94	    /* Work / projects */
95	    .card {
96	      display: block;
97	      background: var(--surface);
98	      border: 1px solid var(--border);
99	      border-radius: 12px;
100	      padding: 20px 24px;
101	      margin-bottom: 16px;
102	      text-decoration: none;
103	      color: inherit;
104	      transition: border-color 0.15s ease, transform 0.15s ease;
105	    }
106	
107	    .card:hover {
108	      border-color: var(--accent);
109	      transform: translateY(-2px);
110	    }
111	
112	    .card h3 {
113	      font-size: 17px;
114	      font-weight: 600;
115	      margin-bottom: 4px;
116	    }
117	
118	    .card p {
119	      font-size: 15px;
120	      color: var(--muted);
121	    }
122	
123	    /* Contact links */
124	    .links {
125	      display: flex;
126	      flex-wrap: wrap;
127	      gap: 12px;
128	    }
129	
130	    .links a {
131	      display: inline-block;
132	      padding: 10px 18px;
133	      border: 1px solid var(--border);
134	      border-radius: 999px;
135	      color: var(--text);
136	      text-decoration: none;
137	      font-size: 15px;
138	      transition: border-color 0.15s ease, color 0.15s ease;
139	    }
140	
141	    .links a:hover {
142	      border-color: var(--accent);
143	      color: var(--accent);
144	    }
145	
146	    footer {
147	      padding: 40px 0 64px;
148	      border-top: 1px solid var(--border);
149	      color: var(--muted);
150	      font-size: 14px;
151	    }
152	
153	    @media (max-width: 480px) {
154	      header {
155	        padding: 64px 0 48px;
156	      }
157	
158	      h1 {
159	        font-size: 32px;
160	      }
161	
162	      .tagline {
163	        font-size: 18px;
164	      }
165	    }
166	  </style>
167	</head>
168	<body>
169	  <div class="container">
170	    <header>
171	      <div class="avatar">AK</div>
172	      <h1>{{userName}}</h1>
173	      <p class="tagline">Software engineer &amp; builder</p>
174	      <p class="intro">
175	        Hi, I'm {{userName}}. I build software and enjoy turning ideas into simple,
176	        well-crafted tools. This is my corner of the internet — a place for
177	        what I'm working on and how to reach me.
178	      </p>
179	    </header>
180	
181	    <section>
182	      <h2>What I'm working on</h2>
183	      <a class="card" href="#">
184	        <h3>Project One</h3>
185	        <p>A short description of what this project does and why it exists.</p>
186	      </a>
187	      <a class="card" href="#">
188	        <h3>Project Two</h3>
189	        <p>Another thing I've built or am currently exploring.</p>
190	      </a>
191	    </section>
192	
193	    <section>
194	      <h2>Get in touch</h2>
195	      <div class="links">
196	        <a href="mailto:<email>">Email</a>
197	        <a href="https://github.com/" target="_blank" rel="noopener">GitHub</a>
198	        <a href="https://www.linkedin.com/" target="_blank" rel="noopener">LinkedIn</a>
199	      </div>
200	    </section>
201	
202	    <footer>
203	      &copy; 2026 {{userName}}
204	    </footer>
205	  </div>
206	</body>
207	</html>
