/* Header / hero */
header {
  position: relative;
  padding: 96px 0 64px;
}

header::before {
  content: "";
  position: absolute;
  top: -160px;
  left: -120px;
  width: 480px;
  height: 480px;
  background: radial-gradient(circle, rgba(94, 234, 212, 0.08), transparent 70%);
  pointer-events: none;
}

.avatar {
  width: 88px;
  height: 88px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--accent), var(--accent-2));
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 32px;
  font-weight: 700;
  color: var(--bg);
  margin-bottom: 24px;
  box-shadow: 0 0 40px rgba(94, 234, 212, 0.25);
}

.card:hover {
  border-color: var(--accent);
  transform: translateY(-2px);
  box-shadow: 0 4px 24px rgba(94, 234, 212, 0.1);
}
